              <span className="modal-title"><i className="fa-solid fa-right-to-bracket" style={{ marginRight: 8 }} />Clock In</span>
              <button className="modal-close" onClick={() => setClockModal(null)}><i className="fa-solid fa-xmark" /></button>
            </div>
            <div className="modal-body">
              <div style={{ textAlign: 'center', marginBottom: 16 }}>
                <div style={{ fontSize: 36, fontWeight: 700, color: '#10B981' }}>
                  {new Date().toLocaleTimeString('en-KE', { hour: '2-digit', minute: '2-digit' })}
                </div>
                <div style={{ color: '#78716C', fontSize: 13 }}>
                  {new Date().toLocaleDateString('en-KE', { weekday: 'long', day: 'numeric', month: 'long' })}
