              <div className="form-group">
                <label className="form-label">Notes (optional)</label>
                <input className="form-input" placeholder="Any notes about this shift..." value={notes} onChange={e => setNotes(e.target.value)} />
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-outline" onClick={() => setClockModal(null)}>Cancel</button>
              <button className="btn btn-primary" onClick={doClockIn} disabled={saving}>
                {saving ? 'Clocking In…' : <><i className="fa-solid fa-right-to-bracket" /> Clock In Now</>}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Clock Out Modal */}
      {clockModal === 'out' && myActiveShift && (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setClockModal(null)}>
          <div className="modal" style={{ maxWidth: 460 }}>
            <div className="modal-header">
              <span className="modal-title"><i className="fa-solid fa-right-from-bracket" style={{ marginRight: 8 }} />Clock Out</span>
              <button className="modal-close" onClick={() => setClockModal(null)}><i className="fa-solid fa-xmark" /></button>
            </div>
            <div className="modal-body">
              <div style={{ background: '#F0FDF4', borderRadius: 8, padding: 12, marginBottom: 16 }}>
                <div style={{ fontSize: 12, color: '#065F46', marginBottom: 4 }}>Elapsed Time</div>
                <LiveDuration clockIn={myActiveShift.clock_in} />
                <div style={{ fontSize: 12, color: '#78716C', marginTop: 4 }}>Started at {fmtTime(myActiveShift.clock_in)}</div>
              </div>
              <div className="form-group">
                <label className="form-label">Break Duration (minutes)</label>
                <input type="number" min="0" max="480" className="form-input" value={breakMins}
                  onChange={e => setBreakMins(e.target.value)} placeholder="0" />
                <div style={{ fontSize: 11, color: '#78716C', marginTop: 4 }}>Break time is deducted from total hours worked.</div>
              </div>
              <div className="form-group">
                <label className="form-label">Notes (optional)</label>
                <input className="form-input" placeholder="End of shift notes..." value={notes} onChange={e => setNotes(e.target.value)} />
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-outline" onClick={() => setClockModal(null)}>Cancel</button>
              <button className="btn btn-danger" onClick={() => doClockOut(myActiveShift)} disabled={saving}>
                {saving ? 'Clocking Out…' : <><i className="fa-solid fa-right-from-bracket" /> Clock Out</>}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
